import React, { useEffect, useMemo, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import api from "../../api/axios";

const AppointmentList = () => {
  const [appointments, setAppointments] = useState([]);
  const [statusFilter, setStatusFilter] = useState("all");
  const [loading, setLoading] = useState(false);
  const [deletingId, setDeletingId] = useState(null);
  const navigate = useNavigate();

  const fetchAppointments = async () => {
    try {
      setLoading(true);
      const res = await api.get("/appointments");
      setAppointments(res.data || []);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load appointments");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAppointments();
  }, []);

  const stats = useMemo(() => {
    const total = appointments.length;
    const scheduled = appointments.filter((a) => a.status === "scheduled").length;
    const completed = appointments.filter((a) => a.status === "completed").length;
    const cancelled = appointments.filter((a) => a.status === "cancelled").length;
    return { total, scheduled, completed, cancelled };
  }, [appointments]);

  const filteredAppointments = useMemo(() => {
    if (statusFilter === "all") return appointments;
    return appointments.filter((a) => a.status === statusFilter);
  }, [appointments, statusFilter]);

  const deleteAppointment = async (id) => {
    if (!window.confirm("Delete this appointment permanently?")) return;

    try {
      setDeletingId(id);
      await api.delete(`/appointments/${id}`);
      setAppointments((prev) => prev.filter((a) => a._id !== id));
      alert("Appointment deleted");
    } catch (err) {
      alert(err.response?.data?.message || "Failed to delete appointment");
    } finally {
      setDeletingId(null);
    }
  };

  const getStatusBadge = (status) => {
    const statusMap = {
      scheduled: "badgeInfo",
      completed: "badgeSuccess",
      cancelled: "badgeDanger",
    };
    return statusMap[status] || "badge";
  };

  return (
    <div className="page">
      {/* Page Header */}
      <div className="pageHead">
        <div>
          <div className="pageTitle">Appointments</div>
          <div className="pageSub">Schedule and manage customer appointments</div>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="kpiGrid">
        <div className="kpiCard">
          <div className="kpiLabel">Total Appointments</div>
          <div className="kpiValue">{loading ? "—" : stats.total}</div>
          <div className="kpiSub">All scheduled events</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Scheduled</div>
          <div className="kpiValue">{loading ? "—" : stats.scheduled}</div>
          <div className="kpiSub">Upcoming</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Completed</div>
          <div className="kpiValue">{loading ? "—" : stats.completed}</div>
          <div className="kpiSub">Finished</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Cancelled</div>
          <div className="kpiValue">{loading ? "—" : stats.cancelled}</div>
          <div className="kpiSub">Cancelled</div>
        </div>
      </div>

      {/* Filter & Actions Card */}
      <div className="card cardPad" style={{ marginBottom: 14 }}>
        <div className="row" style={{ alignItems: "center", flexWrap: "wrap" }}>
          <div>
            <div className="sectionTitle">Appointment Management</div>
            <div className="sub">Filter and manage your appointment schedule</div>
          </div>

          <div style={{ display: "flex", gap: 10, alignItems: "center", marginLeft: "auto", flexWrap: "wrap" }}>
            <select
              className="select"
              style={{ minWidth: 180 }}
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              disabled={loading}
            >
              <option value="all">All Status</option>
              <option value="scheduled">Scheduled</option>
              <option value="completed">Completed</option>
              <option value="cancelled">Cancelled</option>
            </select>

            <button className="btn btnPrimary" onClick={() => navigate("/appointments/add")}>
              ➕ Add Appointment
            </button>
            <button 
              className="btn" 
              onClick={fetchAppointments} 
              disabled={loading}
              style={{ minWidth: 100 }}
            >
              {loading ? "Loading..." : "Refresh"}
            </button>
          </div>
        </div>
      </div>

      {/* Appointments Table */}
      <div className="card cardPad">
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ borderBottom: "2px solid var(--border-light)" }}>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Lead</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Vehicle</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Date</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Time</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Type</th>
              <th style={{ padding: "12px", textAlign: "left", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Status</th>
              <th style={{ padding: "12px", textAlign: "right", fontSize: "14px", fontWeight: "600", color: "var(--text-secondary)" }}>Actions</th>
            </tr>
          </thead>

          <tbody>
            {filteredAppointments.map((a) => (
              <tr key={a._id} style={{ borderBottom: "1px solid var(--border-light)", transition: "background 0.2s" }}>
                <td style={{ padding: "12px", fontWeight: "500", color: "var(--text)" }}>{a.lead?.name || "—"}</td>
                <td style={{ padding: "12px", color: "var(--text-secondary)" }}>
                  {a.vehicle?.brand ? `${a.vehicle.brand} ${a.vehicle.model || a.vehicle.type || ""}` : "—"}
                </td>
                <td style={{ padding: "12px", color: "var(--text-secondary)" }}>
                  {a.date ? new Date(a.date).toLocaleDateString() : "—"}
                </td>
                <td style={{ padding: "12px", color: "var(--text-secondary)" }}>{a.time || "—"}</td>
                <td style={{ padding: "12px", color: "var(--text-secondary)" }}>{a.appointmentType || "—"}</td>
                <td style={{ padding: "12px" }}>
                  <span className={`badge ${getStatusBadge(a.status)}`}>
                    {a.status || "—"}
                  </span>
                </td>
                <td style={{ padding: "12px", textAlign: "right" }}>
                  <button 
                    className="btn btnSmall" 
                    onClick={() => navigate(`/appointments/edit/${a._id}`)}
                    style={{ marginRight: 6 }}
                    disabled={deletingId === a._id}
                  >
                    ✏️ Edit
                  </button>
                  <button
                    className="btn btnSmall"
                    onClick={() => deleteAppointment(a._id)}
                    style={{ background: "var(--danger)", color: "white" }}
                    disabled={deletingId === a._id}
                  >
                    {deletingId === a._id ? "Deleting..." : "🗑️ Delete"}
                  </button>
                </td>
              </tr>
            ))}

            {!loading && filteredAppointments.length === 0 && (
              <tr>
                <td colSpan="7" style={{ padding: "40px", textAlign: "center", color: "var(--text-secondary)" }}>
                  {statusFilter !== "all" ? "No appointments found with this status" : "No appointments scheduled"}
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AppointmentList;
